const START_PORT: u16 = 5000;
const END_PORT: u16 = 5100;
const RELOAD_INTERVAL: Duration = Duration::from_secs(300);
const TICK_INTERVAL: Duration = Duration::from_secs(15);

static THIS_NODE_ID: AtomicI64 = AtomicI64::new(0);

// JOIN that returns one row per (workflow, schedule) with a fully-defined cron
// schedule. LEFT JOINs + COALESCE give wildcard defaults for unset components;
// "Manual" / incomplete schedules collapse to all-wildcards and simply never fire
// a meaningful trigger. Mirrors QuartzSchedulerThread.LoadSql.
const LOAD_SQL: &str = "
    SELECT w.id AS workflow_id, w.name AS workflow_name,
           s.id AS schedule_id, s.name AS schedule_name,
           COALESCE(ce.name, '')  AS cron_every,
           COALESCE(cm.name, '*') AS cron_minute,
           COALESCE(ch.name, '*') AS cron_hour,
           COALESCE(cd.name, '*') AS cron_dom,
           COALESCE(cmo.name, '*') AS cron_month,
           COALESCE(cdow.name, '?') AS cron_dow
    FROM core.workflow w
    JOIN core.schedule s ON s.id = w.schedule_id
    LEFT OUTER JOIN core.cron_every  ce   ON ce.id   = s.cron_every_id
    LEFT OUTER JOIN core.cron_minute cm   ON cm.id   = s.cron_minute_id
    LEFT OUTER JOIN core.cron_hour   ch   ON ch.id   = s.cron_hour_id
    LEFT OUTER JOIN core.cron_dom    cd   ON cd.id   = s.cron_dom_id
    LEFT OUTER JOIN core.cron_month  cmo  ON cmo.id  = s.cron_month_id
    LEFT OUTER JOIN core.cron_dow    cdow ON cdow.id = s.cron_dow_id
    WHERE w.is_active = 1";

struct Scheduled {
    workflow_id: i64,
    workflow_name: String,
    schedule_name: String,
    schedule: Schedule,
    next_fire: DateTime<Utc>,
}

fn main() {
    init_logging();

    let port = match find_port(START_PORT, END_PORT) {
        Some(p) => p,
        None => {
            Logger::error(format!("No available port in range {}-{}", START_PORT, END_PORT));
            std::process::exit(1);
        }
    };
    let addr = format!("0.0.0.0:{}", port);
    println!("Scheduler listening on http://{}", addr);
    Logger::info(format!("Scheduler listening on http://{}", addr));

    install_shutdown_handler();
    std::thread::spawn(move || register_scheduler(port));
    std::thread::spawn(run_scheduler);

    rouille::start_server(addr, move |request| {
        if request.method().eq_ignore_ascii_case("OPTIONS") {
            return with_cors(request, Response::text(""));
        }

        // M2M gate: only the API (or anyone else holding a valid token for
        // this tenant's "scheduler" audience) may reach the scheduler. No
        // per-request principal to set here -- the scheduler already runs
        // every operation on the unchecked logic path.
        match auth0::authenticate_inbound("scheduler", request.header("Authorization")) {
            auth0::AuthOutcome::Unconfigured | auth0::AuthOutcome::Authenticated(_) => {
                let response = handle(request);
                with_cors(request, response)
            }
            auth0::AuthOutcome::Missing => {
                with_cors(request, Response::text("missing bearer token").with_status_code(401))
            }
            auth0::AuthOutcome::Invalid(reason) => {
                Logger::warning(format!("scheduler: JWT validation failed: {}", reason));
                with_cors(request, Response::text("invalid bearer token").with_status_code(401))
            }
        }
    });
}

// ── infrastructure (mirrors the API / agent servers) ─────────────────────────

fn find_port(start: u16, end: u16) -> Option<u16> {
    (start..=end).find(|&p| TcpListener::bind(("0.0.0.0", p)).is_ok())
}

fn init_logging() {
    if let Ok(level) = std::env::var("JUMPSTART_LOG") {
        let level = match level.trim().to_ascii_lowercase().as_str() {
            "debug" => LogLevel::Debug,
            "warning" | "warn" => LogLevel::Warning,
            "error" => LogLevel::Error,
            _ => LogLevel::Info,
        };
        Logger::set_level(level);
    }

    // Make the database log writer available. It is invoked only when the
    // `database` writer is enabled via the `logwriters` config entry; the level
    // and active writers themselves are read from config inside the Logger.
    logic::register_db_log_writer();
}

fn with_cors(request: &Request, response: Response) -> Response {
    let origin = request.header("Origin").unwrap_or("*").to_string();
    response
        .with_additional_header("Access-Control-Allow-Origin", origin)
        .with_additional_header("Access-Control-Allow-Credentials", "true")
        .with_additional_header("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
        .with_additional_header("Access-Control-Allow-Headers", "*")
}

fn install_shutdown_handler() {
    let result = ctrlc::set_handler(|| {
        Logger::info("scheduler: shutdown signal received, marking node Offline");
        set_node_offline();
        std::process::exit(0);
    });
    if let Err(e) = result {
        Logger::warning(format!("scheduler: could not install shutdown handler: {}", e));
    }
}

// ── REST routing ─────────────────────────────────────────────────────────────

fn handle(request: &Request) -> Response {
    // OPTIONS and the auth gate are both handled in main()'s closure before
    // handle() is called.
    let method = request.method().to_ascii_uppercase();
    let url = request.url();
    let path = url.trim_matches('/');
    let segs: Vec<&str> = if path.is_empty() { Vec::new() } else { path.split('/').collect() };

    if segs.len() < 3
        || !segs[0].eq_ignore_ascii_case("api")
        || !segs[1].eq_ignore_ascii_case("scheduler")
    {
        return Response::empty_404();
    }
    let action = segs[2].to_ascii_lowercase();
    let id = segs.get(3).and_then(|s| s.parse::<i64>().ok());

    match (method.as_str(), action.as_str()) {
        ("POST", "execute") => {
            let wid = read_long_body(request).or(id).unwrap_or(0);
            execute(wid);
            Response::json(&json!(wid))
        }
        ("POST", "cancel") | ("POST", "abort") => {
            Logger::info(format!("scheduler: {} {:?}", action, id));
            Response::text("")
        }
        ("GET", "status") => Response::json(&json!({ "workflowId": id.unwrap_or(0), "status": "unknown" })),
        ("POST", "register") => Response::json(&json!(THIS_NODE_ID.load(Ordering::SeqCst))),
        ("POST", "unregister") => {
            set_node_offline();
            Response::text("")
        }
        ("GET", "ping") => Response::json(&json!({ "status": "alive", "timestamp": Util::now_iso8601() })),
        ("GET", "health") => Response::json(&json!({ "status": "healthy" })),
        _ => Response::empty_404(),
    }
}

fn read_long_body(request: &Request) -> Option<i64> {
    let mut s = String::new();
    request.data()?.read_to_string(&mut s).ok()?;
    serde_json::from_str::<Value>(&s).ok()?.as_i64()
}

// ── cron scheduling thread (port of QuartzSchedulerThread) ────────────────────

fn run_scheduler() {
    Logger::info("scheduler: cron thread started");
    let mut scheduled = load_schedules();
    let mut last_reload = Instant::now();

    loop {
        let now = Utc::now();
        for s in scheduled.iter_mut() {
            if now >= s.next_fire {
                Logger::info(format!(
                    "scheduler: trigger fired for workflow {} ({}) | schedule '{}'",
                    s.workflow_id, s.workflow_name, s.schedule_name
                ));
                execute(s.workflow_id);
                match s.schedule.after(&now).next() {
                    Some(next) => s.next_fire = next,
                    None => s.next_fire = now + chrono::Duration::days(3650), // never again
                }
            }
        }

        if last_reload.elapsed() >= RELOAD_INTERVAL {
            Logger::info("scheduler: reloading workflow schedules from database");
            scheduled = load_schedules();
            last_reload = Instant::now();
        }
        std::thread::sleep(TICK_INTERVAL);
    }
}

fn load_schedules() -> Vec<Scheduled> {
    let rows = match DBPersist::select(LOAD_SQL, "default") {
        Ok(r) => r,
        Err(e) => {
            Logger::error(format!("scheduler: failed to load schedules: {}", e));
            return Vec::new();
        }
    };

    let now = Utc::now();
    let mut out = Vec::new();
    for row in &rows {
        let expr = build_cron_expression(row);
        let schedule = match Schedule::from_str(&expr) {
            Ok(s) => s,
            Err(e) => {
                Logger::warning(format!(
                    "scheduler: workflow {} has an unparseable cron '{}': {}",
                    row_i64(row, "workflow_id"),
                    expr,
                    e
                ));
                continue;
            }
        };
        let next_fire = match schedule.after(&now).next() {
            Some(n) => n,
            None => continue, // never fires (e.g. all-wildcard "Manual")
        };
        out.push(Scheduled {
            workflow_id: row_i64(row, "workflow_id"),
            workflow_name: row_str(row, "workflow_name"),
            schedule_name: row_str(row, "schedule_name"),
            schedule,
            next_fire,
        });
    }
    Logger::info(format!("scheduler: {} workflow(s) scheduled", out.len()));
    out
}

/// Assemble a `cron`-crate expression (sec min hour dom month dow year) from the
/// component columns, applying the Every/Exactly modifier and Quartz dom/dow
/// reconciliation, then prepending a fixed "0" seconds and a "*" year.
fn build_cron_expression(row: &Row) -> String {
    let cron_every = row_str(row, "cron_every");
    let minute = apply_every(&row_str(row, "cron_minute"), &cron_every);
    let hour = apply_every(&row_str(row, "cron_hour"), &cron_every);
    let dom = apply_every(&row_str(row, "cron_dom"), &cron_every);
    let month = apply_every(&row_str(row, "cron_month"), &cron_every);
    let dow = apply_every(&row_str(row, "cron_dow"), &cron_every);

    let (dom, dow) = reconcile_dom_dow(&dom, &dow);
    // The `cron` crate treats dom and dow independently (AND); since reconcile
    // leaves at most one of them restricted, mapping `?` to `*` is safe.
    let dom = if dom == "?" { "*".to_string() } else { dom };
    let dow = if dow == "?" { "*".to_string() } else { dow };

    format!("0 {} {} {} {} {} *", minute, hour, dom, month, dow)
}

/// Port of QuartzSchedulerThread.ApplyEvery: wildcards and compound expressions
/// pass through; "Every" turns a plain number N into */N; "Exactly" keeps N.
fn apply_every(value: &str, cron_every: &str) -> String {
    if value.is_empty()
        || value == "*"
        || value == "?"
        || value.contains('/')
        || value.contains('-')
        || value.contains(',')
    {
        return value.to_string();
    }
    if cron_every.eq_ignore_ascii_case("Every") {
        return format!("*/{}", value);
    }
    value.to_string()
}

/// Port of QuartzSchedulerThread.ReconcileDomDow: ensure at most one of dom/dow
/// is specific (the other becomes `?`), matching the Quartz convention.
fn reconcile_dom_dow(dom: &str, dow: &str) -> (String, String) {
    let dom_wild = dom == "*" || dom == "?";
    let dow_wild = dow == "*" || dow == "?";
    if !dom_wild {
        (dom.to_string(), "?".to_string()) // specific dom wins
    } else if !dow_wild {
        ("?".to_string(), dow.to_string())
    } else {
        ("*".to_string(), "?".to_string())
    }
}

// ── dispatch (port of SchedulerLogic.execute / ExecuteWorkflowInternal) ───────

/// Enqueue a workflow for execution. Runs on its own thread so callers (cron
/// thread, REST handler) return immediately.
fn execute(workflow_id: i64) {
    std::thread::spawn(move || execute_workflow_internal(workflow_id));
}

fn execute_workflow_internal(workflow_id: i64) {
    let wf = match exec_get("workflow", workflow_id) {
        Ok(Some(w)) => w,
        _ => {
            Logger::error(format!("scheduler: workflow {} not found", workflow_id));
            return;
        }
    };
    Logger::info(format!(
        "scheduler: executing workflow {} - {}",
        workflow_id,
        jval_str(&wf, "name")
    ));

    // Collect the leaf/child workflows to dispatch.
    let mut children: Vec<Value> = Vec::new();
    if jval_i64(&wf, "workflow_type_id") == WorkflowType::Folder as i64 {
        collect_child_workflows(workflow_id, &mut children);
        if children.is_empty() {
            Logger::info(format!("scheduler: no child workflows for folder {}", workflow_id));
            return;
        }
    } else {
        children.push(wf);
    }

    // Group by seq and dispatch in seq order.
    let mut by_seq: BTreeMap<i64, Vec<Value>> = BTreeMap::new();
    for c in children {
        by_seq.entry(jval_i64(&c, "seq")).or_default().push(c);
    }
    for (seq, group) in by_seq {
        Logger::info(format!("scheduler: dispatching sequence {} ({} workflow(s))", seq, group.len()));
        for child in &group {
            execute_child_workflow(child);
        }
    }
    Logger::info(format!("scheduler: workflow {} dispatch complete", workflow_id));
}

/// Recursively collect child workflows under a folder (via parent_id), folders
/// expanded depth-first. Mirrors SchedulerLogic.CollectChildWorkflows.
fn collect_child_workflows(parent_id: i64, out: &mut Vec<Value>) {
    let sql = format!(
        "SELECT * FROM core.workflow WHERE parent_id = {} and is_active=1 ORDER BY seq",
        parent_id
    );
    let rows = DBPersist::select(&sql, "default").unwrap_or_default();
    for row in &rows {
        let v = row_to_value(row);
        let id = jval_i64(&v, "id");
        let is_folder = jval_i64(&v, "workflow_type_id") == WorkflowType::Folder as i64;
        out.push(v);
        if is_folder {
            collect_child_workflows(id, out);
        }
    }
}

/// Dispatch a single child workflow: Process -> its agent; Folder -> re-queue to
/// the scheduler. Sets the workflow status to Dispatched first (and Failed on a
/// dispatch error), publishing each change so the web UI updates live.
fn execute_child_workflow(child: &Value) {
    let id = jval_i64(child, "id");
    let wtype = jval_i64(child, "workflow_type_id");

    let mut obj = base_object_from_value(child);
    obj.set("exec_status_id", json!(ExecStatus::Dispatched as i64));
    let _ = update_object("workflow", id, &obj);
    publish_workflow_change(id, &obj);

    if wtype == WorkflowType::Process as i64 {
        let assigned_id = jval_i64(child, "server_node_id");
        match resolve_agent(assigned_id) {
            Some((agent_id, url)) => {
                let endpoint = format!("{}/api/scriptagent/execute", url.trim_end_matches('/'));
                let mut req = ureq::post(&endpoint).set("Content-Type", "application/json");
                match auth0::m2m_token("scriptagent") {
                    Ok(Some(token)) => req = req.set("Authorization", &format!("Bearer {}", token)),
                    Ok(None) => {} // M2M not configured for ScriptAgent -- call unauthenticated.
                    Err(e) => Logger::warning(format!(
                        "scheduler: M2M token fetch failed, dispatching workflow {} unauthenticated: {}",
                        id, e
                    )),
                }
                match req.send_string(&id.to_string()) {
                    Ok(_) => Logger::info(format!(
                        "scheduler: dispatched process workflow {} to agent {} ({})",
                        id, agent_id, url
                    )),
                    Err(e) => {
                        Logger::error(format!("scheduler: dispatch of workflow {} failed: {}", id, e));
                        fail_workflow(id, &obj);
                    }
                }
            }
            None => {
                Logger::error(format!(
                    "scheduler: no online ScriptAgent available to run workflow {} (assigned node {})",
                    id, assigned_id
                ));
                fail_workflow(id, &obj);
            }
        }
    } else if wtype == WorkflowType::Folder as i64 {
        Logger::info(format!("scheduler: re-queuing folder workflow {} to scheduler", id));
        execute(id);
    } else {
        Logger::warning(format!("scheduler: unknown workflow type {} for workflow {}", wtype, id));
    }
}

fn fail_workflow(id: i64, base: &BaseObject) {
    let mut obj = base.clone();
    obj.set("exec_status_id", json!(ExecStatus::Failed as i64));
    let _ = update_object("workflow", id, &obj);
    publish_workflow_change(id, &obj);
}

/// Publish a workflow change so web clients update live (the unchecked update
/// path bypasses the proxy's notification hook, as in the agent).
fn publish_workflow_change(workflow_id: i64, wf_obj: &BaseObject) {
    logic::notification::publish("Workflow", workflow_id, wf_obj.to_json());
}

// ── registration / status (mirrors the agent server) ─────────────────────────

fn register_scheduler(port: u16) {
    Util::populate_session_info();

    let computer_name = SessionInfo::get_value("ComputerName", Some("unknown")).unwrap_or_default();
    let ip_address = "0.0.0.0".to_string();
    let url = format!("http://{}:{}", computer_name, port);
    let username = SessionInfo::get_value("UserName", Some("")).unwrap_or_default();
    let user_domain = SessionInfo::get_value("UserDomain", Some("")).unwrap_or_default();
    let os_name = SessionInfo::get_value("OSName", Some("")).unwrap_or_default();
    let os_version = SessionInfo::get_value("OSVersion", Some("")).unwrap_or_default();
    let architecture = SessionInfo::get_value("Architecture", Some("")).unwrap_or_default();

    println!("==============================================");
    println!("Scheduler Registration");
    println!("==============================================");
    println!("Scheduler ID:  {}:{}", computer_name, port);
    println!("URL:           {}", url);
    println!("User:          {}@{}", username, user_domain);
    println!("OS:            {} {} ({})", os_name, os_version, architecture);
    println!("==============================================");

    let mut record = BaseObject::new();
    record.set("hostname", json!(computer_name));
    record.set("server_node_type_id", json!(ServerNodeType::Scheduler as i64));
    record.set("ip_address", json!(ip_address));
    record.set("port", json!(port));
    record.set("url", json!(url));
    record.set("username", json!(username));
    record.set("user_domain", json!(user_domain));
    record.set("os_name", json!(os_name));
    record.set("os_version", json!(os_version));
    record.set("architecture", json!(architecture));
    record.set("registered_at", json!(Util::now_iso8601()));
    record.set("server_node_status_id", json!(ServerNodeStatus::Online as i64));
    record.set("is_active", json!(1));
    record.set("created_by", json!(username));

    let mut ctx = LogicContext::for_record(record);
    match ServerNodeLogic::exec_unchecked("put", &mut ctx) {
        Ok(_) => {
            let id = ctx.transaction.get("id").as_i64().unwrap_or_default();
            THIS_NODE_ID.store(id, Ordering::SeqCst);
            Logger::info(format!("scheduler registered as ServerNode id {} ({})", id, url));
        }
        Err(e) => Logger::error(format!("scheduler registration failed: {}", e)),
    }
}

fn set_node_offline() {
    let node_id = THIS_NODE_ID.load(Ordering::SeqCst);
    if node_id == 0 {
        return;
    }
    if let Ok(Some(node)) = exec_get("servernode", node_id) {
        let mut obj = base_object_from_value(&node);
        obj.set("server_node_status_id", json!(ServerNodeStatus::Offline as i64));
        let _ = update_object("servernode", node_id, &obj);
        Logger::info(format!("scheduler: node {} marked Offline", node_id));
    }
}

// ── logic / persist helpers ──────────────────────────────────────────────────

fn exec_get(object: &str, id: i64) -> Result<Option<Value>, String> {
    let mut ctx = LogicContext::for_id(id);
    match object_exec_unchecked(object, "get", &mut ctx) {
        Ok(Value::Null) => Ok(None),
        Ok(v) => Ok(Some(v)),
        Err(e) => Err(format!("{}", e)),
    }
}

fn update_object(object: &str, id: i64, record: &BaseObject) -> Result<Value, String> {
    let mut ctx = LogicContext::for_record(record.clone());
    ctx.set_arg("id", json!(id));
    object_exec_unchecked(object, "update", &mut ctx).map_err(|e| format!("{}", e))
}

/// Resolve which ScriptAgent to dispatch a Process workflow to, returning
/// `(server_node_id, url)`. Only **online ScriptAgent** nodes are eligible, so a
/// Process is never dispatched to the API or Scheduler node. The workflow's
/// assigned `server_node_id` is preferred when it is one of those online agents;
/// otherwise dispatch falls back to the most recently registered online agent.
/// This keeps dispatch working when the stored `server_node_id` is stale (agents
/// re-register on new ports, so their ids drift) or points at the wrong node
/// type — the cause of a `POST .../api/scriptagent/execute` 404 against a
/// non-agent URL.
fn resolve_agent(preferred_id: i64) -> Option<(i64, String)> {
    let sql = format!(
        "SELECT id, url FROM core.server_node \
         WHERE server_node_type_id = {} AND server_node_status_id = {} AND is_active = 1 \
         ORDER BY registered_at DESC",
        ServerNodeType::Agent as i64,
        ServerNodeStatus::Online as i64
    );
    let rows = DBPersist::select(&sql, "default").ok()?;
    let agents: Vec<(i64, String)> = rows
        .iter()
        .map(|r| (row_i64(r, "id"), row_str(r, "url")))
        .filter(|(_, url)| !url.is_empty())
        .collect();
    if agents.is_empty() {
        return None;
    }
    if let Some(agent) = agents.iter().find(|(agent_id, _)| *agent_id == preferred_id) {
        return Some(agent.clone());
    }
    Logger::warning(format!(
        "scheduler: assigned server_node {} is not an online ScriptAgent; \
         falling back to agent {} ({})",
        preferred_id, agents[0].0, agents[0].1
    ));
    Some(agents[0].clone())
}

fn base_object_from_value(value: &Value) -> BaseObject {
    let mut obj = BaseObject::new();
    if let Value::Object(map) = value {
        for (k, v) in map {
            obj.set(k, v.clone());
        }
    }
    obj
}

fn row_to_value(row: &Row) -> Value {
    Value::Object(row.iter().map(|(k, v)| (k.clone(), v.clone())).collect())
}

fn row_i64(row: &Row, key: &str) -> i64 {
    row.get(key).and_then(|v| v.as_i64()).unwrap_or(0)
}

fn row_str(row: &Row, key: &str) -> String {
    match row.get(key) {
        Some(Value::String(s)) => s.clone(),
        Some(Value::Null) | None => String::new(),
        Some(other) => other.to_string(),
    }
}

fn jval_i64(value: &Value, key: &str) -> i64 {
    value.get(key).and_then(|v| v.as_i64()).unwrap_or(0)
}

fn jval_str(value: &Value, key: &str) -> String {
    value.get(key).and_then(|v| v.as_str()).unwrap_or_default().to_string()
}
